    var p2 = "442";        // Código de área (ejemplo)
    var p3 = "1862246";    // Resto del número (ejemplo)

    var msg = "%C2%A1Hola%20Azu!,%20deseo%20informaci%C3%B3n%20de%20";

    // Al hacer clic, construimos la URL completa y redirigimos
    var finalUrl = "https://wa.me/" + p1 + p2 + p3 + "?text=" + msg;
    window.open(finalUrl, '_blank');

    // Evitamos la acción por defecto del enlace vacío
    e.preventDefault();
  });
