document.addEventListener("DOMContentLoaded", function() {

if (!window.location.href.includes("/search/label/Destacados")) return;

const grid = document.querySelector(".post-grid");
if (!grid) return;

grid.classList.add("home-slider");
grid.parentElement.style.position = "relative";

/* ========= BOTONES ========= */

const leftBtn = document.createElement("button");
const rightBtn = document.createElement("button");

leftBtn.innerHTML = `


`;

rightBtn.innerHTML = `


`;

leftBtn.className = "slider-btn slider-left";
rightBtn.className = "slider-btn slider-right";

grid.parentElement.appendChild(leftBtn);
grid.parentElement.appendChild(rightBtn);

function moverDireccion(direccion){

  const card = grid.querySelector(".post-card");
  if (!card) return;

  const gap = parseInt(window.getComputedStyle(grid).gap) || 0;
  const cardWidth = card.getBoundingClientRect().width + gap;

  const maxScroll = grid.scrollWidth - grid.clientWidth;

  let destino = grid.scrollLeft + (direccion * cardWidth);

  // Limitar dentro de rango válido
  destino = Math.max(0, Math.min(destino, maxScroll));

  grid.scrollTo({
    left: destino,
    behavior: "smooth"
  });
}

leftBtn.onclick = () => moverDireccion(-1);
rightBtn.onclick = () => moverDireccion(1);

/* ========= BARRA ========= */

const scrollbar = document.createElement("div");
scrollbar.className = "slider-scrollbar";

const thumb = document.createElement("div");
thumb.className = "slider-thumb";
thumb.innerHTML = `



`;

scrollbar.appendChild(thumb);
grid.parentElement.appendChild(scrollbar);


/* === HINT PREMIUM RESPONSIVE (NUEVO SVG) === */
const hintMobile = document.createElement("div");
hintMobile.id = "slider-hint-mobile";
hintMobile.className = "slider-hint";

hintMobile.innerHTML = `


`;

grid.parentElement.appendChild(hintMobile);

function controlarHintUnico() {
  // Verificamos si los botones de escritorio están ocultos (esto indica móvil)
  const botonesEscritorioOcultos = window.getComputedStyle(leftBtn).display === "none";
  hintMobile.style.display = botonesEscritorioOcultos ? "flex" : "none";
}

controlarHintUnico();
window.addEventListener("resize", controlarHintUnico);

// Función para ocultar definitivamente
function ocultarHint() {
  hintMobile.classList.add("hide-hint");
  // Opcional: eliminar el evento después de ejecutarse
  grid.removeEventListener("touchstart", ocultarHint);
  grid.removeEventListener("mousedown", ocultarHint);
}

// Escuchamos tanto toque como click por si acaso
grid.addEventListener("touchstart", ocultarHint, {passive: true});
grid.addEventListener("mousedown", ocultarHint);



/* Sincronizar thumb con scroll */

function actualizarThumb(){
  const porcentaje = grid.scrollLeft / (grid.scrollWidth - grid.clientWidth);
  const maxMove = scrollbar.clientWidth - thumb.offsetWidth;
  thumb.style.left = (porcentaje * maxMove) + "px";
}

grid.addEventListener("scroll", actualizarThumb);

/* DRAG UNIVERSAL (Mouse + Touch + iPad) */

let dragging = false;

thumb.addEventListener("pointerdown", (e) => {
  dragging = true;
  thumb.classList.add("active");
  scrollbar.classList.add("active");
  thumb.setPointerCapture(e.pointerId);
  e.preventDefault();
});

thumb.addEventListener("pointermove", (e) => {
  if (!dragging) return;

  e.preventDefault();

  const rect = scrollbar.getBoundingClientRect();
  let x = e.clientX - rect.left - thumb.offsetWidth / 2;

  x = Math.max(0, Math.min(x, rect.width - thumb.offsetWidth));

  thumb.style.left = x + "px";

  const porcentaje = x / (rect.width - thumb.offsetWidth);
  grid.scrollLeft = porcentaje * (grid.scrollWidth - grid.clientWidth);
});

thumb.addEventListener("pointerup", (e) => {
  dragging = false;
  thumb.classList.remove("active");
  scrollbar.classList.remove("active");
  thumb.releasePointerCapture(e.pointerId);
});

/* Posición inicial */
setTimeout(actualizarThumb, 200);

});

// 
document.addEventListener("DOMContentLoaded", function() {
  // Obtenemos la URL actual
  var currentUrl = window.location.href;

  // Buscamos todos los botones del filtro
  var botones = document.querySelectorAll('.fp-btn');

  botones.forEach(function(boton) {
    // Obtenemos el enlace del botón
    var link = boton.getAttribute('href');

    // Si la URL actual contiene el enlace del botón, le ponemos la clase active
    // Usamos decodeURIComponent por si hay tildes o caracteres especiales
    if (currentUrl.includes(decodeURIComponent(link))) {
      boton.classList.add('active');
    }
  });
});
//
